solution_code:
#include <string.h>

#define NPROC 3

typedef struct { int pid; int burst; int queue; } Proc;

void simulate_mlfq(Proc procs[], int nproc, int quantum[]) {
    int time = 0, done = 0;
    while (done < nproc) {
        for (int q = 0; q <= 2; q++) {
            for (int i = 0; i < nproc; i++) {
                if (procs[i].burst <= 0 || procs[i].queue != q) continue;
                int run = (q < 2 && quantum[q] < procs[i].burst) ? quantum[q] : procs[i].burst;
                time += run;
                procs[i].burst -= run;
                if (procs[i].burst <= 0) done++;
                else if (q < 2) procs[i].queue++;
                goto next_round;
            }
        }
        break;
        next_round:;
    }
}

validation.test_code:
void test_simulate_mlfq_single(void) {
    Proc procs[1] = {{1, 3, 0}};
    int quantum[] = {1, 2, 0};
    simulate_mlfq(procs, 1, quantum);
    /* Single process: 3 units in Q0 with quantum=1 */
    /* T0(1) -> Q1, T1(1) -> Q1, T2(1) -> Q2 */
    TEST_ASSERT_EQUAL_INT(0, procs[0].burst);
}

void test_simulate_mlfq_short_process(void) {
    Proc procs[2] = {{1, 1, 0}, {2, 1, 0}};
    int quantum[] = {1, 2, 0};
    simulate_mlfq(procs, 2, quantum);
    /* Both short, terminate in Q0 */
    TEST_ASSERT_EQUAL_INT(0, procs[0].burst);
    TEST_ASSERT_EQUAL_INT(0, procs[1].burst);
}

void test_simulate_mlfq_three_standard(void) {
    Proc procs[3] = {
        {1, 4, 0},
        {2, 2, 0},
        {3, 1, 0}
    };
    int quantum[] = {1, 2, 0};
    simulate_mlfq(procs, 3, quantum);
    /* P1: Q0(1) Q1(2) Q2(1) = 4 */
    /* P2: Q0(1) Q1(1) = 2 */
    /* P3: Q0(1) = 1 */
    TEST_ASSERT_EQUAL_INT(0, procs[0].burst);
    TEST_ASSERT_EQUAL_INT(0, procs[1].burst);
    TEST_ASSERT_EQUAL_INT(0, procs[2].burst);
}

void test_simulate_mlfq_queue_levels(void) {
    Proc procs[1] = {{1, 5, 0}};
    int quantum[] = {2, 2, 0};
    simulate_mlfq(procs, 1, quantum);
    /* Q0: 2 units (demoted) */
    /* Q1: 2 units (demoted) */
    /* Q2: 1 unit (done) */
    TEST_ASSERT_EQUAL_INT(0, procs[0].burst);
}

int main(void) {
    RUN_TEST(test_simulate_mlfq_single);
    RUN_TEST(test_simulate_mlfq_short_process);
    RUN_TEST(test_simulate_mlfq_three_standard);
    RUN_TEST(test_simulate_mlfq_queue_levels);
    TEST_SUMMARY();
    return _clings_failures > 0 ? 1 : 0;
}

